// ─── Helper utilities ────────────────────────────────────────────────────────
export const getQuestById = (id: string) => quests.find((q) => q.id === id);
export const getHiddenGems = () => quests.filter((q) => q.isHiddenGem);
export const getLateNightQuests = () => quests.filter((q) => q.openLate);
export const getQuestsByCategory = (cat: string) => quests.filter((q) => q.category === cat);
export const getQuestsByMood = (mood: string) => quests.filter((q) => q.moods.includes(mood as any));
export const getQuestsByEnergy = (energy: string) => quests.filter((q) => q.energy === energy);
export const getQuestsByBestTime = (time: string) =>
  quests.filter((q) => q.bestTime === time || q.bestTime === "anytime");
export const getRandomQuests = (count: number): Quest[] => {
  const shuffled = [...quests].sort(() => Math.random() - 0.5);
  const result: Quest[] = [];
  const usedCategories = new Set<string>();
  for (const q of shuffled) {
    if (result.length >= count) break;
    if (!usedCategories.has(q.category)) { result.push(q); usedCategories.add(q.category); }
  }
  for (const q of shuffled) {
    if (result.length >= count) break;
    if (!result.find((r) => r.id === q.id)) result.push(q);
  }
  return result.slice(0, count);
};
export const getAllCategories = () => Array.from(new Set(quests.map((q) => q.category))).sort();
export const getAllTags = () => Array.from(new Set(quests.flatMap((q) => q.tags))).sort();
